using Microsoft.Extensions.DependencyInjection;
using Microsoft.Extensions.Hosting;
using Microsoft.Extensions.Logging;
using McpServer.Tools;
using McpServer.Prompts;

var builder = Host.CreateApplicationBuilder(args);

// Redirect all logging to stderr so it never corrupts the stdio JSON-RPC stream.
builder.Logging.ClearProviders();
builder.Logging.AddConsole(options => options.LogToStandardErrorThreshold = LogLevel.Trace);

builder.Services.AddHttpClient("ExternalApi", client =>
{
    client.BaseAddress = new Uri(
        builder.Configuration["ExternalApi:BaseUrl"] ?? "https://api.example.com");
    client.DefaultRequestHeaders.Add("Accept", "application/json");
});

builder.Services
    .AddMcpServer(options =>
    {
        options.ServerInfo = new() { Name = "mcp-demo-server", Version = "1.0.0" };
    })
    .WithStdioServerTransport()
    .WithTools<ApiTools>()
    .WithPrompts<SummarizationPrompts>();

await builder.Build().RunAsync();

