using System.ComponentModel;
using System.Text.Json;
using Microsoft.Extensions.Logging;
using ModelContextProtocol.Server;

namespace McpServer.Tools;

[McpServerToolType]
public sealed class ApiTools
{
    [McpServerTool(Name = "fetch_data"), Description("Fetches JSON data from an external API endpoint.")]
    public static async Task<string> FetchDataAsync(
        IHttpClientFactory httpClientFactory,
        ILogger<ApiTools> logger,
        [Description("Relative path appended to the API base URL (e.g. \"/users/1\").")] string path,
        CancellationToken cancellationToken)
    {
        using var client = httpClientFactory.CreateClient("ExternalApi");

        logger.LogInformation("Calling external API: {Path}", path);

        using var response = await client.GetAsync(path, cancellationToken);
        response.EnsureSuccessStatusCode();

        var json = await response.Content.ReadAsStringAsync(cancellationToken);

        // Pretty-print so the LLM can read it easily.
        using var doc = JsonDocument.Parse(json);
        return JsonSerializer.Serialize(doc, new JsonSerializerOptions { WriteIndented = true });
    }
}

using System.ComponentModel;
using ModelContextProtocol.Protocol;
using ModelContextProtocol.Server;

namespace McpServer.Prompts;

[McpServerPromptType]
public sealed class SummarizationPrompts
{
    [McpServerPrompt(Name = "summarize"), Description("Generates a prompt that asks the model to summarize the given text.")]
    public static IList<PromptMessage> Summarize(
        [Description("The text to summarize.")] string text,
        [Description("Optional target length hint (e.g. \"2 sentences\", \"100 words\").")] string? length = null)
    {
        var instruction = length is not null
            ? $"Summarize the following text in approximately {length}."
            : "Summarize the following text concisely.";

        return
        [
            new()
            {
                Role = Role.User,
                Content = new TextContentBlock { Text = $"{instruction}\n\n{text}" },
            },
        ];
    }
}

